import React, { useEffect } from 'react';
import styled from 'styled-components';
import { useTheme } from '../context/ThemeContext';
import { PageWrapper, ContentContainer, Section, Header } from '../components/common/PageWrapper';
import Footer from '../components/Footer';
import AOS from 'aos';
import 'aos/dist/aos.css';

const EventsContainer = styled.div`
  min-height: 100vh;
  background: ${props => props.theme.background};
  padding-top: 80px;
  transition: background-color 0.3s ease;
`;

const EventGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(350px, 1fr));
  gap: 30px;
  padding: 20px;
`;

const EventCard = styled.div`
  background: ${props => props.theme.cardBackground};
  border: 1px solid ${props => props.theme.cardBorder};
  border-radius: 15px;
  overflow: hidden;
  transition: all 0.3s ease;

  img {
    width: 100%;
    height: 200px;
    object-fit: cover;
  }

  .content {
    padding: 20px;

    h3 {
      color: ${props => props.theme.primary};
      margin-bottom: 10px;
    }

    p {
      color: ${props => props.theme.text};
      margin-bottom: 15px;
    }

    .date {
      color: ${props => props.theme.secondary};
      font-size: 0.9rem;
    }
  }

  &:hover {
    transform: translateY(-5px);
    box-shadow: ${props => props.theme.shadow};
  }
`;

const Events = () => {
  const { theme } = useTheme();

  useEffect(() => {
    AOS.init({
      duration: 1000,
      once: true
    });
  }, []);

  const events = [
    {
      title: "Optimus Arena 2025",
      date: "March 15-17, 2025",
      description: "Annual flagship hackathon event featuring 48 hours of coding, innovation, and collaboration.",
      image: require("../assets/events/hackathon.jpg")
    },
    // Add more events here
  ];

  return (
    <PageWrapper theme={theme}>
      <EventsContainer theme={theme}>
        <Section>
          <Header theme={theme}>
            <h2 data-aos="fade-up">Our Events</h2>
          </Header>
          <EventGrid>
            {events.map((event, index) => (
              <EventCard 
                key={index} 
                theme={theme}
                data-aos="fade-up"
                data-aos-delay={100 * (index % 4)}
              >
                <img src={event.image} alt={event.title} />
                <div className="content">
                  <h3>{event.title}</h3>
                  <p>{event.description}</p>
                  <div className="date">{event.date}</div>
                </div>
              </EventCard>
            ))}
          </EventGrid>
        </Section>
        <Footer />
      </EventsContainer>
    </PageWrapper>
  );
};

export default Events;
